#include<bits/stdc++.h>
using namespace std;
int n, m, arr;
bool v[20000011] = {0};
bool a[20000010];
long long b[20000010],k = 0 ,d[20000101];
void it(int n){
    for (int i = 1; i <= n; i++) {
        d[i] = 1;
    }
	for (int i = 2; i <= n; i++) {
			if (!a[i]) {
				b[k++] = i;
                d[i]=-1;
			}
			for (int j = 0; j<k && i * b[j] <= n; j++) {
				a[b[j]*i] = 1;
				if (i % b[j] == 0) {
					d[i*b[j]]=0;
					break;
				}else{
					d[i*b[j]]=-d[i];
				}
			}
		}
}
int main() {
	cin >> n >> m;
	it(m);
	for(int j=n;j<=m;j++) arr+=d[j];
	cout << arr;
	return 0;
}
